from crewai.flow.flow import Flow, start, listen

class MyFlow(Flow):

    @start()
    def first_step(self):
        print("This runs first")
        return "hello"

    @start()              # also runs on kickoff, concurrently with first_step
    def another_entry(self):
        print("This also runs first")
        return "world"

class PipelineFlow(Flow):

    @start()
    def step_one(self):
        return "data from step one"

    @listen(step_one)                        # <-- pass the method itself
    def step_two(self, data_from_one: str):  # receives return value
        print(f"Got: {data_from_one}")
        return data_from_one.upper()

    @listen(step_two)
    def step_three(self, data: str):
        print(f"Final: {data}")

class BroadcastFlow(Flow):

    @start()
    def produce_a(self):
        return "output A"

    @start()
    def produce_b(self):
        return "output B"

    @listen(produce_a)  # called once when produce_a finishes
    @listen(produce_b)  # called again when produce_b finishes
    def consume(self, result: str):
        print(f"Received: {result}")  # prints twice

from crewai.flow.flow import Flow, start, listen, or_

class RaceFlow(Flow):

    @start()
    def fast_source(self):
        return "fast result"

    @start()
    def slow_source(self):
        return "slow result"

    @listen(or_(fast_source, slow_source))
    def use_first_result(self, result: str):
        # Called when the first of the two starts completes
        # In practice both run concurrently — whichever returns first triggers this
        print(f"First result: {result}")

from crewai.flow.flow import Flow, start, listen, and_

class JoinFlow(Flow):

    @start()
    def section_a(self):
        return "section A content"

    @start()
    def section_b(self):
        return "section B content"

    @start()
    def section_c(self):
        return "section C content"

    @listen(and_(section_a, section_b, section_c))
    def merge(self, results: list):
        # results is a list of all three return values
        combined = "\n\n".join(str(r) for r in results)
        self.state.merged = combined
        return combined

from crewai.flow.flow import Flow, start, listen, router
from pydantic import BaseModel

class ReviewState(BaseModel):
    draft: str = ""
    feedback: str = ""

class ReviewFlow(Flow[ReviewState]):

    @start()
    def write(self):
        self.state.draft = "A short draft."

    @router(write)
    def review(self):
        word_count = len(self.state.draft.split())
        if word_count >= 10:
            return "approved"
        else:
            self.state.feedback = f"Too short: only {word_count} words."
            return "rejected"

    @listen("approved")     # only runs if router returned "approved"
    def publish(self):
        print("Publishing:", self.state.draft)

    @listen("rejected")     # only runs if router returned "rejected"
    def revise(self):
        print("Revise:", self.state.feedback)

class TriageFlow(Flow[ReviewState]):

    @start()
    def classify(self):
        self.state.draft = "Some content"
        return "content"

    @router(classify)
    def triage(self):
        words = len(self.state.draft.split())
        if words < 5:
            return "too_short"
        elif words > 500:
            return "too_long"
        else:
            return "acceptable"

    @listen("acceptable")
    @router(triage)           # this branch also routes
    def quality_check(self):
        if "error" in self.state.draft:
            return "has_errors"
        return "clean"

    @listen("clean")
    def approve(self):
        print("Document approved")

    @listen("has_errors")
    def flag_errors(self):
        print("Document has errors — flagging for review")

    @listen("too_short")
    def expand(self):
        print("Document too short — requesting expansion")

    @listen("too_long")
    def summarise(self):
        print("Document too long — requesting summarisation")

class FlexFlow(Flow):

    @start()
    def source_a(self):
        return "a"

    @start()
    def source_b(self):
        return "b"

    # Triggered by source_a, AND also acts as a router
    @listen(source_a)
    @router(source_a)
    def process_a(self, data: str):
        if data == "a":
            return "route_x"
        return "route_y"

    @listen("route_x")
    def branch_x(self):
        print("Taking route X")

    @listen("route_y")
    def branch_y(self):
        print("Taking route Y")

class MixedFlow(Flow[ReviewState]):

    @start()
    def process(self):
        # Plain Python inside the step — no decorators needed
        items = ["item1", "item2", "item3"]
        results = []
        for item in items:
            result = item.upper()   # process each item
            results.append(result)

        self.state.draft = ", ".join(results)

        # Router decision using a decorator on a separate method
        return self.state.draft

    @router(process)
    def route(self, draft: str):
        return "done" if draft else "empty"

    @listen("done")
    def publish(self):
        print(self.state.draft)

from pydantic import BaseModel
from crewai.flow.flow import Flow, start, listen, router

class RetryState(BaseModel):
    draft: str = ""
    attempts: int = 0
    max_attempts: int = 3
    passed: bool = False

class RetryFlow(Flow[RetryState]):

    @start()
    def generate(self):
        self.state.attempts += 1
        # Simulate generation — in practice call a Crew
        self.state.draft = f"Draft attempt {self.state.attempts}"

    @router(generate)
    def validate(self):
        word_count = len(self.state.draft.split())
        if word_count >= 5:
            self.state.passed = True
            return "pass"
        elif self.state.attempts < self.state.max_attempts:
            return "retry"
        else:
            return "give_up"

    @listen("retry")
    def retry_generate(self):
        # Duplicate of generate — loops back through validate
        self.state.attempts += 1
        self.state.draft = f"Improved draft attempt {self.state.attempts}"

    @listen("pass")
    def publish(self):
        print(f"Published after {self.state.attempts} attempt(s): {self.state.draft}")

    @listen("give_up")
    def abort(self):
        print(f"Gave up after {self.state.attempts} attempts")

class ConcurrentFlow(Flow):

    @start()
    def a(self): return "A"   # |
                              # |-- run concurrently
    @start()
    def b(self): return "B"   # |

    @listen(a)
    def after_a(self, val): return val + "1"  # waits for a

    @listen(b)
    def after_b(self, val): return val + "2"  # waits for b, independent of after_a

    @listen(and_(after_a, after_b))
    def join(self, results: list):            # waits for both
        print(results)

# Option 1: print inside each step
class DebugFlow(Flow):
    @start()
    def step_a(self):
        print("[step_a] starting")
        result = "a"
        print(f"[step_a] done → {result}")
        return result

    @listen(step_a)
    def step_b(self, val):
        print(f"[step_b] received {val!r}")

# Option 2: override on_flow_start / on_flow_end
class InstrumentedFlow(Flow):
    def on_flow_start(self):
        print("Flow starting")
    def on_flow_end(self):
        print("Flow complete")

# Option 3: plot the DAG (opens HTML in browser)
flow = InstrumentedFlow()
flow.plot("my_flow_dag")   # saves my_flow_dag.html

from pydantic import BaseModel
from crewai.flow.flow import Flow, start, listen, router
from crewai import Agent, Task, Crew

class DocState(BaseModel):
    topic: str = ""
    draft: str = ""
    review: str = ""
    attempts: int = 0

class DocFlow(Flow[DocState]):

    @start()
    def kickoff(self):
        pass  # state.topic already set by kickoff(inputs=...)

    @listen(kickoff)
    def write_draft(self):
        self.state.attempts += 1
        writer = Agent(role="Writer", goal="Write a 300-word article on {topic}", backstory="...")
        task = Task(description="Write on {topic}", expected_output="300-word article", agent=writer)
        result = Crew(agents=[writer], tasks=[task]).kickoff(
            inputs={"topic": self.state.topic})
        self.state.draft = result.raw

    @router(write_draft)
    def review_draft(self):
        reviewer = Agent(role="Reviewer", goal="Review quality", backstory="...")
        task = Task(
            description=f"Review this draft — reply APPROVED or REJECTED:\n{self.state.draft}",
            expected_output="APPROVED or REJECTED: <reason>",
            agent=reviewer,
        )
        result = Crew(agents=[reviewer], tasks=[task]).kickoff()
        self.state.review = result.raw
        if "APPROVED" in result.raw:
            return "approved"
        elif self.state.attempts >= 3:
            return "give_up"
        return "retry"

    @listen("retry")
    def revise(self):
        # Re-enter write_draft with incremented attempts
        self.state.attempts += 1
        writer = Agent(role="Writer", goal="Improve the draft based on feedback", backstory="...")
        task = Task(
            description=f"Revise this draft:\n{self.state.draft}\n\nFeedback:\n{self.state.review}",
            expected_output="Improved 300-word article",
            agent=writer,
        )
        result = Crew(agents=[writer], tasks=[task]).kickoff()
        self.state.draft = result.raw

    @listen("approved")
    def publish(self):
        print(f"Published after {self.state.attempts} attempt(s)")
        return self.state.draft

    @listen("give_up")
    def escalate(self):
        print(f"Escalating to human editor after {self.state.attempts} failed attempts")
